import React, { useState, useEffect, useMemo } from "react";
import { api } from "../utils/api";

const styles = {
  container: {
    fontFamily: "'JetBrains Mono', monospace",
    backgroundColor: "#0B0F14",
    color: "#E5E7DB",
    padding: 20,
    borderRadius: 10,
    maxWidth: 480,
    margin: "auto",
    userSelect: "none",
  },
  label: {
    display: "block",
    marginBottom: 8,
    fontWeight: "600",
    fontSize: 14,
  },
  input: {
    width: "100%",
    padding: "8px 10px",
    borderRadius: 6,
    border: "1px solid #1F2A37",
    backgroundColor: "#0F1620",
    color: "#E5E7DB",
    fontSize: 14,
    outline: "none",
    boxSizing: "border-box",
  },
  inputPrice: {
    fontFamily: "'JetBrains Mono', monospace",
    fontSize: 14,
    color: "#60A5FA",
  },
  select: {
    width: "100%",
    padding: "8px 10px",
    borderRadius: 6,
    border: "1px solid #1F2A37",
    backgroundColor: "#0F1620",
    color: "#E5E7DB",
    fontSize: 14,
    outline: "none",
    boxSizing: "border-box",
    appearance: "none",
    WebkitAppearance: "none",
    MozAppearance: "none",
    cursor: "pointer",
  },
  toggleGroup: {
    display: "flex",
    gap: 12,
    marginTop: 8,
    marginBottom: 16,
  },
  toggleButton: {
    flex: 1,
    padding: "8px 0",
    borderRadius: 6,
    border: "1px solid #1F2A37",
    fontWeight: "600",
    fontSize: 14,
    cursor: "pointer",
    userSelect: "none",
    textAlign: "center",
    transition: "background-color 0.25s",
  },
  toggleButtonBuy: {
    backgroundColor: "#0F1620",
    color: "#22C55E",
    borderColor: "#22C55E",
  },
  toggleButtonSell: {
    backgroundColor: "#0F1620",
    color: "#EF4444",
    borderColor: "#EF4444",
  },
  toggleButtonActiveBuy: {
    backgroundColor: "#22C55E",
    color: "#0B0F14",
    borderColor: "#22C55E",
  },
  toggleButtonActiveSell: {
    backgroundColor: "#EF4444",
    color: "#0B0F14",
    borderColor: "#EF4444",
  },
  checkboxLabel: {
    display: "inline-flex",
    alignItems: "center",
    gap: 8,
    fontSize: 14,
    cursor: "pointer",
    userSelect: "none",
  },
  checkboxInput: {
    cursor: "pointer",
  },
  autocompleteContainer: {
    position: "relative",
    width: "100%",
  },
  autocompleteList: {
    position: "absolute",
    top: "100%",
    left: 0,
    right: 0,
    backgroundColor: "#0F1620",
    border: "1px solid #1F2A37",
    borderTop: "none",
    maxHeight: 150,
    overflowY: "auto",
    zIndex: 10,
    borderRadius: "0 0 4px 4px",
  },
  autocompleteItem: {
    padding: "8px 10px",
    cursor: "pointer",
    fontSize: 14,
  },
  autocompleteItemHover: {
    backgroundColor: "#1F2A37",
  },
  orderSummary: {
    backgroundColor: "#0F1620",
    border: "1px solid #1F2A37",
    borderRadius: 6,
    padding: 12,
    marginTop: 20,
    fontSize: 14,
    lineHeight: 1.4,
  },
  submitButton: {
    marginTop: 20,
    width: "100%",
    padding: "12px 0",
    fontWeight: "700",
    fontSize: 16,
    borderRadius: 6,
    border: "none",
    cursor: "pointer",
    backgroundColor: "#60A5FA",
    color: "#0B0F14",
    userSelect: "none",
    transition: "background-color 0.25s",
  },
  submitButtonDisabled: {
    backgroundColor: "#1F2A37",
    cursor: "not-allowed",
  },
  errorText: {
    color: "#EF4444",
    fontSize: 13,
    marginTop: 4,
  },
};

function FractionalOrderEntry() {
  const [symbols, setSymbols] = useState([]);
  const [symbolInput, setSymbolInput] = useState("");
  const [filteredSymbols, setFilteredSymbols] = useState([]);
  const [showAutocomplete, setShowAutocomplete] = useState(false);
  const [selectedSymbol, setSelectedSymbol] = useState(null);

  const [orderType, setOrderType] = useState("Market");
  const [side, setSide] = useState("Buy");
  const [quantity, setQuantity] = useState("");
  const [isDollarAmount, setIsDollarAmount] = useState(false);
  const [limitPrice, setLimitPrice] = useState("");
  const [stopPrice, setStopPrice] = useState("");
  const [timeInForce, setTimeInForce] = useState("DAY");

  const [inputErrors, setInputErrors] = useState({});

  // Fetch symbols once on mount
  useEffect(() => {
    async function fetchSymbols() {
      try {
        const data = await api("/data/cache/symbols");
        if (!data) throw new Error("Failed to fetch symbols");
        // Expecting data to be array of strings or objects with symbol property
        if (Array.isArray(data)) {
          setSymbols(
            data.map((item) =>
              typeof item === "string" ? item.toUpperCase() : item.symbol?.toUpperCase() || ""
            )
          );
        }
      } catch {
        setSymbols([]);
      }
    }
    fetchSymbols();
  }, []);

  // Filter symbols for autocomplete
  useEffect(() => {
    if (symbolInput.trim() === "") {
      setFilteredSymbols([]);
      return;
    }
    const inputUpper = symbolInput.trim().toUpperCase();
    const filtered = symbols.filter((sym) => sym.startsWith(inputUpper)).slice(0, 10);
    setFilteredSymbols(filtered);
  }, [symbolInput, symbols]);

  // Close autocomplete on outside click
  useEffect(() => {
    function handleClickOutside(e) {
      if (!e.target.closest("#symbol-autocomplete-container")) {
        setShowAutocomplete(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Validate inputs and set errors
  useEffect(() => {
    const errors = {};

    if (!selectedSymbol) {
      errors.symbol = "Please select a valid symbol.";
    }

    const qtyNum = parseFloat(quantity);
    if (isNaN(qtyNum) || qtyNum <= 0) {
      errors.quantity = "Quantity must be a positive number.";
    } else if (!/^\d*\.?\d*$/.test(quantity)) {
      errors.quantity = "Quantity must be a valid decimal number.";
    }

    if (orderType === "Limit" || orderType === "Stop Limit") {
      const lp = parseFloat(limitPrice);
      if (isNaN(lp) || lp <= 0) {
        errors.limitPrice = "Limit price must be a positive number.";
      }
    }

    if (orderType === "Stop" || orderType === "Stop Limit") {
      const sp = parseFloat(stopPrice);
      if (isNaN(sp) || sp <= 0) {
        errors.stopPrice = "Stop price must be a positive number.";
      }
    }

    setInputErrors(errors);
  }, [selectedSymbol, quantity, orderType, limitPrice, stopPrice]);

  // Estimated cost calculation
  // If dollar amount mode: estimated cost = quantity input (dollars)
  // If share mode: estimated cost = quantity * price (limit/stop/market price)
  // For Market orders, no price input, so estimated cost unknown (show N/A)
  // For Stop orders, estimated cost unknown (show N/A)
  // For Limit and Stop Limit, use limit price
  // For simplicity, if price unknown, show N/A

  const estimatedCost = useMemo(() => {
    const qtyNum = parseFloat(quantity);
    if (isNaN(qtyNum) || qtyNum <= 0) return null;

    if (isDollarAmount) {
      return qtyNum;
    }

    // Determine price to use
    let price = null;
    if (orderType === "Market") {
      return null; // unknown price
    }
    if (orderType === "Limit") {
      const lp = parseFloat(limitPrice);
      if (!isNaN(lp) && lp > 0) price = lp;
    }
    if (orderType === "Stop") {
      return null; // unknown price
    }
    if (orderType === "Stop Limit") {
      const lp = parseFloat(limitPrice);
      if (!isNaN(lp) && lp > 0) price = lp;
    }
    if (price === null) return null;

    return qtyNum * price;
  }, [quantity, isDollarAmount, orderType, limitPrice]);

  // Format price/cost with 2 decimals and $ sign
  function formatPrice(val) {
    if (val === null || val === undefined || isNaN(val)) return "N/A";
    return `$${val.toFixed(2)}`;
  }

  // Handle symbol input change
  function onSymbolInputChange(e) {
    const val = e.target.value.toUpperCase();
    setSymbolInput(val);
    setShowAutocomplete(true);
    setSelectedSymbol(null);
  }

  // Handle symbol selection from autocomplete
  function onSelectSymbol(sym) {
    setSelectedSymbol(sym);
    setSymbolInput(sym);
    setShowAutocomplete(false);
  }

  // Handle side toggle
  function onSideToggle(newSide) {
    setSide(newSide);
  }

  // Handle order type change
  function onOrderTypeChange(e) {
    setOrderType(e.target.value);
    // Clear limit and stop prices on order type change
    setLimitPrice("");
    setStopPrice("");
  }

  // Handle time in force change
  function onTimeInForceChange(e) {
    setTimeInForce(e.target.value);
  }

  // Handle quantity change
  function onQuantityChange(e) {
    const val = e.target.value;
    // Allow only digits and dot
    if (/^\d*\.?\d*$/.test(val)) {
      setQuantity(val);
    }
  }

  // Handle limit price change
  function onLimitPriceChange(e) {
    const val = e.target.value;
    if (/^\d*\.?\d*$/.test(val)) {
      setLimitPrice(val);
    }
  }

  // Handle stop price change
  function onStopPriceChange(e) {
    const val = e.target.value;
    if (/^\d*\.?\d*$/.test(val)) {
      setStopPrice(val);
    }
  }

  // Handle dollar amount toggle
  function onDollarAmountToggle(e) {
    setIsDollarAmount(e.target.checked);
    setQuantity("");
  }

  // Check if form is valid for submit
  const isFormValid = useMemo(() => {
    if (Object.keys(inputErrors).length > 0) return false;
    if (!selectedSymbol) return false;
    if (quantity === "" || parseFloat(quantity) <= 0) return false;
    if ((orderType === "Limit" || orderType === "Stop Limit") && (limitPrice === "" || parseFloat(limitPrice) <= 0))
      return false;
    if ((orderType === "Stop" || orderType === "Stop Limit") && (stopPrice === "" || parseFloat(stopPrice) <= 0))
      return false;
    return true;
  }, [inputErrors, selectedSymbol, quantity, orderType, limitPrice, stopPrice]);

  // Submit handler
  function onSubmit(e) {
    e.preventDefault();
    if (!isFormValid) return;
    // Compose order object
    const order = {
      symbol: selectedSymbol,
      side,
      orderType,
      quantity: parseFloat(quantity),
      isDollarAmount,
      limitPrice: orderType === "Limit" || orderType === "Stop Limit" ? parseFloat(limitPrice) : null,
      stopPrice: orderType === "Stop" || orderType === "Stop Limit" ? parseFloat(stopPrice) : null,
      timeInForce,
      estimatedCost,
    };
    // For demo, just alert JSON
    alert("Order submitted:\n" + JSON.stringify(order, null, 2));
  }

  return (
    <form style={styles.container} onSubmit={onSubmit} noValidate>
      <div style={{ marginBottom: 16 }}>
        <label htmlFor="symbol-input" style={styles.label}>
          Symbol
        </label>
        <div id="symbol-autocomplete-container" style={styles.autocompleteContainer}>
          <input
            id="symbol-input"
            type="text"
            autoComplete="off"
            spellCheck="false"
            style={styles.input}
            value={symbolInput}
            onChange={onSymbolInputChange}
            onFocus={() => setShowAutocomplete(true)}
            aria-autocomplete="list"
            aria-controls="symbol-listbox"
            aria-expanded={showAutocomplete}
            aria-haspopup="listbox"
            aria-activedescendant={null}
            placeholder="Start typing symbol..."
          />
          {showAutocomplete && filteredSymbols.length > 0 && (
            <ul role="listbox" id="symbol-listbox" style={styles.autocompleteList}>
              {filteredSymbols.map((sym) => (
                <li
                  key={sym}
                  role="option"
                  tabIndex={-1}
                  style={styles.autocompleteItem}
                  onMouseDown={(e) => {
                    // prevent blur before click
                    e.preventDefault();
                    onSelectSymbol(sym);
                  }}
                  onKeyDown={(e) => {
                    if (e.key === "Enter" || e.key === " ") {
                      e.preventDefault();
                      onSelectSymbol(sym);
                    }
                  }}
                >
                  {sym}
                </li>
              ))}
            </ul>
          )}
        </div>
        {inputErrors.symbol && <div style={styles.errorText}>{inputErrors.symbol}</div>}
      </div>

      <div style={{ marginBottom: 16 }}>
        <label htmlFor="order-type" style={styles.label}>
          Order Type
        </label>
        <select id="order-type" style={styles.select} value={orderType} onChange={onOrderTypeChange}>
          <option value="Market">Market</option>
          <option value="Limit">Limit</option>
          <option value="Stop">Stop</option>
          <option value="Stop Limit">Stop Limit</option>
        </select>
      </div>

      <div style={styles.toggleGroup} role="radiogroup" aria-label="Side">
        <button
          type="button"
          aria-pressed={side === "Buy"}
          onClick={() => onSideToggle("Buy")}
          style={{
            ...styles.toggleButton,
            ...styles.toggleButtonBuy,
            ...(side === "Buy" ? styles.toggleButtonActiveBuy : {}),
          }}
        >
          Buy
        </button>
        <button
          type="button"
          aria-pressed={side === "Sell"}
          onClick={() => onSideToggle("Sell")}
          style={{
            ...styles.toggleButton,
            ...styles.toggleButtonSell,
            ...(side === "Sell" ? styles.toggleButtonActiveSell : {}),
          }}
        >
          Sell
        </button>
      </div>

      <div style={{ marginBottom: 16 }}>
        <label htmlFor="quantity-input" style={styles.label}>
          {isDollarAmount ? "Dollar Amount" : "Quantity (Shares)"}
        </label>
        <input
          id="quantity-input"
          type="text"
          inputMode="decimal"
          pattern="^\d*\.?\d*$"
          style={styles.input}
          value={quantity}
          onChange={onQuantityChange}
          placeholder={isDollarAmount ? "Enter dollar amount" : "Enter quantity"}
          aria-describedby="quantity-error"
        />
        {inputErrors.quantity && (
          <div id="quantity-error" style={styles.errorText}>
            {inputErrors.quantity}
          </div>
        )}
        <label style={{ ...styles.checkboxLabel, marginTop: 8 }}>
          <input
            type="checkbox"
            checked={isDollarAmount}
            onChange={onDollarAmountToggle}
            style={styles.checkboxInput}
          />
          Enter as dollar amount
        </label>
      </div>

      {(orderType === "Limit" || orderType === "Stop Limit") && (
        <div style={{ marginBottom: 16 }}>
          <label htmlFor="limit-price-input" style={styles.label}>
            Limit Price
          </label>
          <input
            id="limit-price-input"
            type="text"
            inputMode="decimal"
            pattern="^\d*\.?\d*$"
            style={{ ...styles.input, ...styles.inputPrice }}
            value={limitPrice}
            onChange={onLimitPriceChange}
            placeholder="Enter limit price"
            aria-describedby="limit-price-error"
          />
          {inputErrors.limitPrice && (
            <div id="limit-price-error" style={styles.errorText}>
              {inputErrors.limitPrice}
            </div>
          )}
        </div>
      )}

      {(orderType === "Stop" || orderType === "Stop Limit") && (
        <div style={{ marginBottom: 16 }}>
          <label htmlFor="stop-price-input" style={styles.label}>
            Stop Price
          </label>
          <input
            id="stop-price-input"
            type="text"
            inputMode="decimal"
            pattern="^\d*\.?\d*$"
            style={{ ...styles.input, ...styles.inputPrice }}
            value={stopPrice}
            onChange={onStopPriceChange}
            placeholder="Enter stop price"
            aria-describedby="stop-price-error"
          />
          {inputErrors.stopPrice && (
            <div id="stop-price-error" style={styles.errorText}>
              {inputErrors.stopPrice}
            </div>
          )}
        </div>
      )}

      <div style={{ marginBottom: 16 }}>
        <label htmlFor="time-in-force" style={styles.label}>
          Time in Force
        </label>
        <select id="time-in-force" style={styles.select} value={timeInForce} onChange={onTimeInForceChange}>
          <option value="DAY">DAY</option>
          <option value="GTC">GTC</option>
          <option value="IOC">IOC</option>
        </select>
      </div>

      <div style={styles.orderSummary} aria-live="polite" aria-atomic="true">
        <div>
          <strong>Order Summary</strong>
        </div>
        <div>Symbol: {selectedSymbol || "N/A"}</div>
        <div>Side: {side}</div>
        <div>
          Quantity: {quantity || "N/A"} {isDollarAmount ? "dollars" : "shares"}
        </div>
        <div>Order Type: {orderType}</div>
        {(orderType === "Limit" || orderType === "Stop Limit") && (
          <div>Limit Price: {limitPrice ? formatPrice(parseFloat(limitPrice)) : "N/A"}</div>
        )}
        {(orderType === "Stop" || orderType === "Stop Limit") && (
          <div>Stop Price: {stopPrice ? formatPrice(parseFloat(stopPrice)) : "N/A"}</div>
        )}
        <div>Time in Force: {timeInForce}</div>
        <div>
          Estimated Cost:{" "}
          <span style={{ color: "#60A5FA", fontFamily: "'JetBrains Mono', monospace" }}>
            {estimatedCost !== null ? formatPrice(estimatedCost) : "N/A"}
          </span>
        </div>
      </div>

      <button
        type="submit"
        disabled={!isFormValid}
        style={{
          ...styles.submitButton,
          ...(isFormValid ? {} : styles.submitButtonDisabled),
        }}
        aria-disabled={!isFormValid}
      >
        Submit Order
      </button>
    </form>
  );
}

export default FractionalOrderEntry;
